def twoSum(nums, target):
    seen = {}          # dictionary: value -> index
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return [seen[complement], i]
        seen[num] = i
    return []

def isValid(s):
    stack = []
    mapping = {')': '(', '}': '{', ']': '['}

    for char in s:
        if char in mapping:          # closing bracket
            top = stack.pop() if stack else '#'
            if mapping[char] != top:
                return False
        else:                        # opening bracket
            stack.append(char)

    return len(stack) == 0

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def mergeTwoLists(l1, l2):
    dummy = ListNode(0)    # placeholder start node
    current = dummy

    while l1 and l2:
        if l1.val <= l2.val:
            current.next = l1
            l1 = l1.next
        else:
            current.next = l2
            l2 = l2.next
        current = current.next

    current.next = l1 or l2  # attach remaining nodes
    return dummy.next

def removeDuplicates(nums):
    if not nums:
        return 0

    k = 1  # first element is always unique

    for i in range(1, len(nums)):
        if nums[i] != nums[k - 1]:  # found new unique element
            nums[k] = nums[i]
            k += 1

    return k

def searchInsert(nums, target):
    left, right = 0, len(nums) - 1

    while left <= right:
        mid = (left + right) // 2
        if nums[mid] == target:
            return mid
        elif nums[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return left  # insert position when not found

def plusOne(digits):
    for i in range(len(digits) - 1, -1, -1):
        if digits[i] < 9:
            digits[i] += 1
            return digits
        digits[i] = 0   # this digit becomes 0, carry over

    return [1] + digits  # all digits were 9 → [1, 0, 0, ...]

def deleteDuplicates(head):
    current = head

    while current and current.next:
        if current.val == current.next.val:
            current.next = current.next.next  # skip duplicate
        else:
            current = current.next  # move to next different node

    return head

def merge(nums1, m, nums2, n):
    # Start from the END to avoid overwriting
    i, j, k = m - 1, n - 1, m + n - 1

    while i >= 0 and j >= 0:
        if nums1[i] > nums2[j]:
            nums1[k] = nums1[i]
            i -= 1
        else:
            nums1[k] = nums2[j]
            j -= 1
        k -= 1

    # If nums2 has leftover elements
    nums1[:j + 1] = nums2[:j + 1]

def maxDepth(root):
    if not root:
        return 0

    left_depth = maxDepth(root.left)
    right_depth = maxDepth(root.right)

    return 1 + max(left_depth, right_depth)

def maxProfit(prices):
    min_price = float('inf')  # lowest buy price seen
    max_profit = 0

    for price in prices:
        if price < min_price:
            min_price = price       # found a better buy day
        elif price - min_price > max_profit:
            max_profit = price - min_price  # found better profit

    return max_profit

def singleNumber(nums):
    result = 0
    for num in nums:
        result ^= num  # XOR each number
    return result

class MinStack:
    def __init__(self):
        self.stack = []
        self.min_stack = []  # parallel stack tracking minimums

    def push(self, val):
        self.stack.append(val)
        # min_stack top is always current minimum
        if not self.min_stack or val <= self.min_stack[-1]:
            self.min_stack.append(val)

    def pop(self):
        val = self.stack.pop()
        if val == self.min_stack[-1]:
            self.min_stack.pop()

    def top(self):
        return self.stack[-1]

    def getMin(self):
        return self.min_stack[-1]

def getIntersectionNode(headA, headB):
    a, b = headA, headB

    while a != b:
        a = a.next if a else headB
        b = b.next if b else headA

    return a

def majorityElement(nums):
    # Boyer-Moore Voting Algorithm
    count = 0
    candidate = None

    for num in nums:
        if count == 0:
            candidate = num  # pick new candidate
        count += (1 if num == candidate else -1)

    return candidate

def isAnagram(s, t):
    from collections import Counter
    return Counter(s) == Counter(t)

def missingNumber(nums):
    n = len(nums)
    expected = n * (n + 1) // 2  # sum of 0..n
    return expected - sum(nums)

def moveZeroes(nums):
    insert_pos = 0  # position to write next non-zero

    for num in nums:
        if num != 0:
            nums[insert_pos] = num
            insert_pos += 1

    # Fill remaining positions with zeros
    while insert_pos < len(nums):
        nums[insert_pos] = 0
        insert_pos += 1

def reverseString(s):
    left, right = 0, len(s) - 1

    while left < right:
        s[left], s[right] = s[right], s[left]  # swap
        left += 1
        right -= 1

def intersect(nums1, nums2):
    from collections import Counter
    c1 = Counter(nums1)
    c2 = Counter(nums2)

    result = []
    for num in c1:
        if num in c2:
            count = min(c1[num], c2[num])  # take minimum occurrence
            result.extend([num] * count)

    return result

def findDisappearedNumbers(nums):
    # Mark visited indices as negative
    for num in nums:
        idx = abs(num) - 1  # convert to 0-indexed
        if nums[idx] > 0:
            nums[idx] = -nums[idx]  # negate to mark as visited

    # Indices still positive → those numbers are missing
    return [i + 1 for i, val in enumerate(nums) if val > 0]

def fib(n):
    if n <= 1:
        return n

    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b  # slide window forward

    return b

def search(nums, target):
    left, right = 0, len(nums) - 1

    while left <= right:
        mid = left + (right - left) // 2  # avoid integer overflow

        if nums[mid] == target:
            return mid
        elif nums[mid] < target:
            left = mid + 1   # search right half
        else:
            right = mid - 1  # search left half

    return -1

def middleNode(head):
    slow = fast = head

    while fast and fast.next:
        slow = slow.next        # moves 1 step
        fast = fast.next.next  # moves 2 steps

    return slow

def addBinary(a, b):
    res = []
    carry = 0
    i, j = len(a) - 1, len(b) - 1

    while i >= 0 or j >= 0 or carry:
        total = carry
        if i >= 0:
            total += int(a[i])
            i -= 1
        if j >= 0:
            total += int(b[j])
            j -= 1
        res.append(str(total % 2))
        carry = total // 2

    return "".join(reversed(res))

def isSymmetric(root):
    def isMirror(t1, t2):
        if not t1 and not t2: return True
        if not t1 or not t2: return False
        return (t1.val == t2.val) and                isMirror(t1.right, t2.left) and                isMirror(t1.left, t2.right)
    return isMirror(root, root)

def hasPathSum(root, targetSum):
    if not root: return False

    targetSum -= root.val
    if not root.left and not root.right:
        return targetSum == 0

    return hasPathSum(root.left, targetSum) or            hasPathSum(root.right, targetSum)

def generate(numRows):
    res = [[1]]
    for i in range(1, numRows):
        row = [1]
        for j in range(1, i):
            row.append(res[i-1][j-1] + res[i-1][j])
        row.append(1)
        res.append(row)
    return res

def isPalindrome(s):
    l, r = 0, len(s) - 1
    while l < r:
        if not s[l].isalnum(): l += 1
        elif not s[r].isalnum(): r -= 1
        else:
            if s[l].lower() != s[r].lower():
                return False
            l += 1
            r -= 1
    return True

def hasCycle(head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow == fast:
            return True
    return False

def isHappy(n):
    seen = set()
    while n != 1 and n not in seen:
        seen.add(n)
        n = sum(int(digit)**2 for digit in str(n))
    return n == 1

def removeElements(head, val):
    dummy = ListNode(0, head)
    curr = dummy
    while curr.next:
        if curr.next.val == val:
            curr.next = curr.next.next
        else:
            curr = curr.next
    return dummy.next

def isIsomorphic(s, t):
    mapST, mapTS = {}, {}
    for c1, c2 in zip(s, t):
        if (c1 in mapST and mapST[c1] != c2) or            (c2 in mapTS and mapTS[c2] != c1):
            return False
        mapST[c1] = c2
        mapTS[c2] = c1
    return True

def addDigits(n):
    if n == 0: return 0
    return 1 + (n - 1) % 9

def canConstruct(ransomNote, magazine):
    from collections import Counter
    mag_count = Counter(magazine)
    rs_count = Counter(ransomNote)

    for char, count in rs_count.items():
        if mag_count[char] < count:
            return False
    return True

def firstUniqChar(s):
    count = collections.Counter(s)
    for i, char in enumerate(s):
        if count[char] == 1:
            return i
    return -1

def isSubsequence(s, t):
    if not s: return True
    i = 0
    for char in t:
        if i < len(s) and char == s[i]:
            i += 1
    return i == len(s)

def islandPerimeter(grid):
    rows, cols = len(grid), len(grid[0])
    perimeter = 0
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 1:
                perimeter += 4
                if r > 0 and grid[r-1][c] == 1: perimeter -= 2
                if c > 0 and grid[r][c-1] == 1: perimeter -= 2
    return perimeter

def diameterOfBinaryTree(root):
    self.res = 0
    def dfs(node):
        if not node: return 0
        l, r = dfs(node.left), dfs(node.right)
        self.res = max(self.res, l + r)
        return 1 + max(l, r)
    dfs(root)
    return self.res

def canPlaceFlowers(flowerbed, n):
    count = 0
    bed = [0] + flowerbed + [0]
    for i in range(1, len(bed) - 1):
        if bed[i-1] == 0 and bed[i] == 0 and bed[i+1] == 0:
            bed[i] = 1
            count += 1
    return count >= n

def searchBST(root, val):
    if not root or root.val == val:
        return root

    if val < root.val:
        return searchBST(root.left, val)
    return searchBST(root.right, val)

class KthLargest:
    def __init__(self, k, nums):
        self.k = k
        self.heap = nums
        heapq.heapify(self.heap)
        while len(self.heap) > k:
            heapq.heappop(self.heap)

    def add(self, val):
        heapq.heappush(self.heap, val)
        if len(self.heap) > self.k:
            heapq.heappop(self.heap)
        return self.heap[0]

class MyHashSet:
    def __init__(self):
        self.size = 1000
        self.table = [[] for _ in range(self.size)]

    def _hash(self, key):
        return key % self.size

    def add(self, key):
        if not self.contains(key):
            self.table[self._hash(key)].append(key)

    def remove(self, key):
        h = self._hash(key)
        if key in self.table[h]:
            self.table[h].remove(key)

    def contains(self, key):
        return key in self.table[self._hash(key)]

class MyHashMap:
    def __init__(self):
        self.size = 1000
        self.table = [[] for _ in range(self.size)]

    def _hash(self, key):
        return key % self.size

    def put(self, key, value):
        h = self._hash(key)
        for i, (k, v) in enumerate(self.table[h]):
            if k == key:
                self.table[h][i] = (key, value)
                return
        self.table[h].append((key, value))

    def get(self, key):
        h = self._hash(key)
        for k, v in self.table[h]:
            if k == key: return v
        return -1

def pivotIndex(nums):
    total = sum(nums)
    left_sum = 0
    for i, x in enumerate(nums):
        if left_sum == (total - left_sum - x):
            return i
        left_sum += x
    return -1

def minCostClimbingStairs(cost):
    cost.append(0) # the floor above last step
    for i in range(len(cost) - 3, -1, -1):
        cost[i] += min(cost[i + 1], cost[i + 2])
    return min(cost[0], cost[1])

def backspaceCompare(s, t):
    def build(S):
        stack = []
        for c in S:
            if c != '#': stack.append(c)
            elif stack: stack.pop()
        return "".join(stack)
    return build(s) == build(t)

def lemonadeChange(bills):
    five = ten = 0
    for b in bills:
        if b == 5: five += 1
        elif b == 10:
            if not five: return False
            five -= 1; ten += 1
        else:
            if ten and five: ten -= 1; five -= 1
            elif five >= 3: five -= 3
            else: return False
    return True

def isMonotonic(nums):
    inc = dec = True
    for i in range(len(nums) - 1):
        if nums[i] > nums[i+1]: inc = False
        if nums[i] < nums[i+1]: dec = False
    return inc or dec

def numUniqueEmails(emails):
    unique = set()
    for e in emails:
        local, domain = e.split('@')
        local = local.split('+')[0].replace('.', '')
        unique.add(local + '@' + domain)
    return len(unique)

class RecentCounter:
    def __init__(self):
        self.q = collections.deque()

    def ping(self, t):
        self.q.append(t)
        while self.q[0] < t - 3000:
            self.q.popleft()
        return len(self.q)

def rangeSumBST(root, low, high):
    self.sum = 0
    def dfs(node):
        if not node: return
        if low <= node.val <= high:
            self.sum += node.val
        if node.val > low:
            dfs(node.left)
        if node.val < high:
            dfs(node.right)
    dfs(root)
    return self.sum

def validMountainArray(arr):
    n = len(arr)
    if n < 3: return False
    i = 0
    while i + 1 < n and arr[i] < arr[i + 1]:
        i += 1
    if i == 0 or i == n - 1: return False
    while i + 1 < n and arr[i] > arr[i + 1]:
        i += 1
    return i == n - 1

def diStringMatch(s):
    l, r = 0, len(s)
    res = []
    for c in s:
        if c == 'I':
            res.append(l); l += 1
        else:
            res.append(r); r -= 1
    res.append(l)
    return res

def minDeletionSize(strs):
    count = 0
    for col in range(len(strs[0])):
        for row in range(len(strs) - 1):
            if strs[row][col] > strs[row + 1][col]:
                count += 1
                break
    return count

def isAlienSorted(words, order):
    order_map = {c: i for i, c in enumerate(order)}
    for i in range(len(words) - 1):
        w1, w2 = words[i], words[i+1]
        for j in range(len(w1)):
            if j == len(w2): return False
            if w1[j] != w2[j]:
                if order_map[w1[j]] > order_map[w2[j]]:
                    return False
                break
    return True

def repeatedNTimes(nums):
    seen = set()
    for x in nums:
        if x in seen: return x
        seen.add(x)
    return -1

def isUnivalTree(root):
    val = root.val
    def dfs(node):
        if not node: return True
        if node.val != val: return False
        return dfs(node.left) and dfs(node.right)
    return dfs(root)

def sortedSquares(nums):
    n = len(nums)
    res = [0] * n
    l, r = 0, n - 1
    for i in range(n-1, -1, -1):
        if abs(nums[l]) > abs(nums[r]):
            res[i] = nums[l] ** 2
            l += 1
        else:
            res[i] = nums[r] ** 2
            r -= 1
    return res

def addToArrayForm(num, k):
    res = []
    i = len(num) - 1
    while i >= 0 or k > 0:
        if i >= 0:
            k += num[i]
            i -= 1
        res.append(k % 10)
        k //= 10
    return res[::-1]

def isCousins(root, x, y):
    res = [] # store (parent, depth)
    def dfs(node, p, d):
        if not node or len(res) == 2: return
        if node.val == x or node.val == y:
            res.append((p, d))
        dfs(node.left, node, d + 1)
        dfs(node.right, node, d + 1)
    dfs(root, None, 0)
    return res[0][0] != res[1][0] and res[0][1] == res[1][1]

def findJudge(n, trust):
    scores = [0] * (n + 1)
    for a, b in trust:
        scores[a] -= 1
        scores[b] += 1
    for i in range(1, n + 1):
        if scores[i] == n - 1:
            return i
    return -1

def commonChars(words):
    res = collections.Counter(words[0])
    for w in words[1:]:
        res &= collections.Counter(w)
    return list(res.elements())

def largestSumAfterKNegations(nums, k):
    nums.sort()
    for i in range(len(nums)):
        if nums[i] < 0 and k > 0:
            nums[i] *= -1
            k -= 1
    if k % 2 == 1:
        nums.sort()
        nums[0] *= -1
    return sum(nums)

def romanToInt(s):
    roman = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    for i in range(len(s)):
        if i + 1 < len(s) and roman[s[i]] < roman[s[i+1]]:
            total -= roman[s[i]]
        else:
            total += roman[s[i]]
    return total

def longestCommonPrefix(strs):
    if not strs: return ""
    prefix = strs[0]
    for i in range(1, len(strs)):
        while not strs[i].startswith(prefix):
            prefix = prefix[:-1]
            if not prefix: return ""
    return prefix

def removeElement(nums, val):
    k = 0
    for i in range(len(nums)):
        if nums[i] != val:
            nums[k] = nums[i]
            k += 1
    return k

def strStr(haystack, needle):
    if not needle: return 0
    for i in range(len(haystack) - len(needle) + 1):
        if haystack[i:i+len(needle)] == needle:
            return i
    return -1

def isBalanced(root):
    def check(node):
        if not node: return 0
        left = check(node.left)
        if left == -1: return -1
        right = check(node.right)
        if right == -1: return -1
        if abs(left - right) > 1: return -1
        return 1 + max(left, right)
    return check(root) != -1

def minDepth(root):
    if not root: return 0
    if not root.left: return 1 + minDepth(root.right)
    if not root.right: return 1 + minDepth(root.left)
    return 1 + min(minDepth(root.left), minDepth(root.right))

def getRow(rowIndex):
    row = [1] * (rowIndex + 1)
    for i in range(1, rowIndex):
        for j in range(i, 0, -1):
            row[j] += row[j-1]
    return row

def majorityElement(nums):
    candidate, count = None, 0
    for num in nums:
        if count == 0:
            candidate = num
        count += (1 if num == candidate else -1)
    return candidate

def titleToNumber(s):
    res = 0
    for char in s:
        val = ord(char) - ord('A') + 1
        res = res * 26 + val
    return res

def reverseBits(n):
    res = 0
    for _ in range(32):
        res = (res << 1) | (n & 1)
        n >>= 1
    return res

def hammingWeight(n):
    count = 0
    while n:
        n &= (n - 1)
        count += 1
    return count

def containsNearbyDuplicate(nums, k):
    seen = {}
    for i, num in enumerate(nums):
        if num in seen and i - seen[num] <= k:
            return True
        seen[num] = i
    return False

def summaryRanges(nums):
    res = []
    i = 0
    while i < len(nums):
        start = nums[i]
        while i + 1 < len(nums) and nums[i+1] == nums[i] + 1:
            i += 1
        if start != nums[i]:
            res.append(f"{start}->{nums[i]}")
        else:
            res.append(f"{start}")
        i += 1
    return res

def wordPattern(pattern, s):
    words = s.split()
    if len(pattern) != len(words): return False
    return len(set(zip(pattern, words))) == len(set(pattern)) == len(set(words))

def countBits(n):
    res = [0] * (n + 1)
    for i in range(1, n + 1):
        res[i] = res[i >> 1] + (i & 1)
    return res

def longestPalindrome(s):
    odds = set()
    for char in s:
        if char in odds: odds.remove(char)
        else: odds.add(char)
    return len(s) - len(odds) + (1 if odds else 0)

def findContentChildren(g, s):
    g.sort(); s.sort()
    i = j = 0
    while i < len(g) and j < len(s):
        if s[j] >= g[i]:
            i += 1
        j += 1
    return i

def findMaxConsecutiveOnes(nums):
    res = count = 0
    for n in nums:
        if n == 1:
            count += 1
            res = max(res, count)
        else:
            count = 0
    return res

def constructRectangle(area):
    w = int(area**0.5)
    while area % w != 0:
        w -= 1
    return [area // w, w]

def findPoisonedDuration(ts, d):
    if not ts: return 0
    total = 0
    for i in range(len(ts)-1):
        total += min(d, ts[i+1] - ts[i])
    return total + d

def nextGreaterElement(nums1, nums2):
    stack, mapping = [], {}
    for n in nums2:
        while stack and stack[-1] < n:
            mapping[stack.pop()] = n
        stack.append(n)
    return [mapping.get(n, -1) for n in nums1]

def findWords(words):
    r1, r2, r3 = set("qwertyuiop"), set("asdfghjkl"), set("zxcvbnm")
    res = []
    for w in words:
        s = set(w.lower())
        if s <= r1 or s <= r2 or s <= r3:
            res.append(w)
    return res

def findRelativeRanks(score):
    sorted_score = sorted(score, reverse=True)
    mapping = {}
    for i, s in enumerate(sorted_score):
        if i == 0: mapping[s] = "Gold Medal"
        elif i == 1: mapping[s] = "Silver Medal"
        elif i == 2: mapping[s] = "Bronze Medal"
        else: mapping[s] = str(i + 1)
    return [mapping[s] for s in score]

def checkPerfectNumber(num):
    if num <= 1: return False
    s = 1
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            s += i + num // i
    return s == num

def findLUSlength(a, b):
    if a == b: return -1
    return max(len(a), len(b))

def maxDepth(root):
    if not root: return 0
    if not root.children: return 1
    return 1 + max(maxDepth(c) for c in root.children)
